#!/bin/bash
set -e
DIR="/home/klinker/klinkeroblik"
mkdir -p "$DIR/data" "$DIR/handlers" "$DIR/utils" "$DIR/locales"

decode() {
    echo "$2" | base64 -d > "$DIR/$1"
}

decode "config.py" ""
decode "database.py" ""
decode "models.py" ""
decode "bot.py" ""
decode "utils/__init__.py" "IyB1dGlscyBwYWNrYWdlCg=="
decode "utils/i18n.py" ""
decode "utils/keyboards.py" ""
decode "utils/permissions.py" ""
decode "handlers/__init__.py" "IyBoYW5kbGVycyBwYWNrYWdlCg=="
decode "handlers/start.py" ""
decode "handlers/menu.py" ""
decode "handlers/work_entry.py" ""
decode "handlers/reports.py" ""
decode "handlers/brigades.py" ""
decode "handlers/projects.py" ""
decode "handlers/rates.py" ""
decode "handlers/work_types.py" ""
decode "handlers/settings.py" ""
decode "locales/uk.json" ""
decode "locales/pl.json" ""
decode "locales/ru.json" ""
decode "requirements.txt" "cHl0aG9uLXRlbGVncmFtLWJvdFtleHRdPT0yMC43ClNRTEFsY2hlbXlbYXN5bmNpb109PTIuMC4yNQphaW9zcWxpdGU9PTAuMTkuMApweXRob24tZG90ZW52PT0xLjAuMAo="

# Create .env
if [ ! -f "$DIR/.env" ]; then
    echo "BOT_TOKEN=8540947079:AAEA7jlmbozLHw-ueQdFNSK0zizAqZk0Voc" > "$DIR/.env"
    echo "DATABASE_URL=sqlite+aiosqlite:///data/klinkeroblik.db" >> "$DIR/.env"
fi

chown -R klinker:klinker "$DIR"

echo ""
echo "=== Files created! ==="
echo ""

# Install Python deps
sudo -u klinker bash -c "cd $DIR && python3 -m venv venv && source venv/bin/activate && pip install --quiet -r requirements.txt"

echo "=== Dependencies installed! ==="

# Create systemd service
cat > /etc/systemd/system/klinkeroblik.service << 'SVC'
[Unit]
Description=KlinkerOblik Telegram Bot
After=network.target

[Service]
Type=simple
User=klinker
Group=klinker
WorkingDirectory=/home/klinker/klinkeroblik
Environment="PATH=/home/klinker/klinkeroblik/venv/bin:/usr/bin"
ExecStart=/home/klinker/klinkeroblik/venv/bin/python3 /home/klinker/klinkeroblik/bot.py
Restart=always
RestartSec=10

[Install]
WantedBy=multi-user.target
SVC

systemctl daemon-reload
systemctl enable klinkeroblik
systemctl start klinkeroblik
sleep 3

if systemctl is-active --quiet klinkeroblik; then
    echo ""
    echo "=== Bot is RUNNING! ==="
    echo "Open Telegram and press /start"
    echo ""
else
    echo "ERROR: Bot failed to start. Check: journalctl -u klinkeroblik -n 30"
fi
